function parseRange(s) {
  const parts = s.split('-');
  if (parts.length === 2) {
    const [a, b] = parts.map(Number);
    if (a <= b) {
      return Array.from({ length: b - a + 1 }, (_, i) => a + i);
    } else {
      return Array.from({ length: a - b + 1 }, (_, i) => a - i);
    }
  }
  return [Number(s)];
}
